import subprocess,re
r = subprocess.run(['pandoc','documents/original-postnuptial-agreement.docx','-t','plain'],capture_output=True,text=True)
t = re.sub(r'\s+',' ',r.stdout)
for marker in ['10,000) without the prior written consent','reimburse Husband for Wife','pro rata to each Party','in violation of this Section shall be the sole']:
    i = t.find(marker)
    print(('ORIG FOUND ' if i>=0 else 'ORIG MISS  ')+repr(marker))
    if i>=0: print('   ...'+t[i-60:i+150]+'...')
print()
r2 = subprocess.run(['pandoc','documents/redlined-postnuptial-agreement.docx','-t','plain'],capture_output=True,text=True)
t2 = re.sub(r'\s+',' ',r2.stdout)
for marker in ['compounded monthly','is not intended to address','equitably between the Parties','does not address, issues of child custody','Each Party shall indemnify and hold the other Party harmless from any liability arising from such Party']:
    i = t2.find(marker)
    print(('REDL FOUND ' if i>=0 else 'REDL MISS  ')+repr(marker))
    if i>=0: print('   ...'+t2[i-50:i+150]+'...')
""}

